{
  "outputStyle": "explanatory",
  "effortLevel": "high",
  "skipDangerousModePermissionPrompt": false,
  "env": {
    "NODE_ENV": "development",
    "DEBUG": "true"
  },
  "permissions": {
    "allow": ["Bash(npm:*)", "Bash(git:*)", "Bash(npx:*)"],
    "deny": ["Bash(rm:-rf)"],
    "additionalDirectories": ["/home/testuser/projects"]
  },
  "hooks": {
    "PostToolUse": [
      {
        "matcher": "Edit|Write",
        "hooks": [
          { "type": "command", "command": "npx prettier --write $CLAUDE_TOOL_OUTPUT", "timeout": 5000 }
        ]
      }
    ],
    "Stop": [
      {
        "hooks": [
          { "type": "command", "command": "notify-send 'Claude Code' 'Session ended'" }
        ]
      }
    ]
  },
  "enabledPlugins": {
    "prettier": true,
    "eslint": true,
    "git-tools": false
  },
  "statusLine": {
    "type": "command",
    "command": "echo 'dev-setup profile'"
  }
}

{
  "team_name": "backup-tests",
  "description": "Backup modülü için vitest kurulumu, Tauri mock'ları ve unit testlerin yazılması",
  "createdAt": "2026-03-24T07:30:00.000Z",
  "members": [
    { "name": "setup-agent", "agentId": "setup-agent@backup-tests", "agentType": "ccm-tdd" },
    { "name": "mock-agent", "agentId": "mock-agent@backup-tests", "agentType": "ccm-tdd" },
    { "name": "test-writer", "agentId": "test-writer@backup-tests", "agentType": "ccm-tdd" }
  ]
}

{
  "name": "prettier",
  "version": "1.2.0",
  "enabled": true,
  "config": {
    "singleQuote": true,
    "trailingComma": "es5",
    "printWidth": 100,
    "semi": true
  }
}

{
  "name": "eslint",
  "version": "2.0.1",
  "enabled": true,
  "config": {
    "extends": ["eslint:recommended", "plugin:@typescript-eslint/recommended"],
    "rules": {
      "no-console": "warn",
      "@typescript-eslint/no-explicit-any": "error"
    }
  }
}

{
  "name": "git-tools",
  "version": "0.9.0",
  "enabled": false,
  "config": {
    "autoStage": false,
    "signCommits": true
  }
}

{
  "mcpServers": {
    "filesystem": {
      "type": "stdio",
      "command": "npx",
      "args": ["-y", "@modelcontextprotocol/server-filesystem", "/home/testuser/projects"]
    },
    "github": {
      "type": "stdio",
      "command": "npx",
      "args": ["-y", "@modelcontextprotocol/server-github"],
      "env": { "GITHUB_PERSONAL_ACCESS_TOKEN": "ghp_placeholder" }
    },
    "brave-search": {
      "type": "stdio",
      "command": "npx",
      "args": ["-y", "@modelcontextprotocol/server-brave-search"],
      "env": { "BRAVE_API_KEY": "placeholder" },
      "disabled": true
    }
  },
  "projects": {
    "/home/testuser/projects/my-app": {
      "hasTrustDialogAccepted": true,
      "mcpServers": {
        "local-db": {
          "type": "stdio",
          "command": "node",
          "args": ["./mcp-server/index.js"]
        }
      }
    },
    "/home/testuser/projects/api-service": {
      "hasTrustDialogAccepted": true
    }
  }
}
